#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; long long C; scanf("%d %d %lld", &N, &M, &C);
        long long *A = (long long*)malloc(N*sizeof(long long));
        long long *B = (long long*)malloc(M*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        for(int i=0;i<M;i++) scanf("%lld", &B[i]);
        int i=0,j=0; // i items taken from A, j from B
        int progressed=1;
        while(progressed){
            progressed=0;
            while(i<N && (A[i] + i - j) <= C){
                i++; progressed=1;
            }
            while(j<M && (B[j] - i + j) <= C){
                j++; progressed=1;
            }
        }
        if(i==N && j==M) printf("Yes\n"); else printf("No\n");
        free(A); free(B);
    }
    return 0;
}

