import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            long C = fs.nextLong();
            long[] A = new long[N];
            long[] B = new long[M];
            for (int i = 0; i < N; i++) A[i] = fs.nextLong();
            for (int i = 0; i < M; i++) B[i] = fs.nextLong();
            int i = 0, j = 0;
            boolean progress = true;
            while (progress) {
                progress = false;
                while (i < N && A[i] + i - j <= C) { i++; progress = true; }
                while (j < M && B[j] - i + j <= C) { j++; progress = true; }
            }
            sb.append(i == N && j == M ? "Yes" : "No").append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

